#include <bits/stdc++.h>
using namespace std;
int n,t,m,a[21],dp[21][21][21];
//dp[i][j][k]为前i首歌，用j个盘，其中最后一个盘用k的时间的答案
int main(){
	scanf("%d%d%d",&n,&t,&m);
	for(int i=1;i<=n;i++)
		scanf("%d",&a[i]);
	for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++){
			for(int k=0;k<=t;k++){
				if(k==0)
					dp[i][j][k]=dp[i][j-1][t];
				else if(a[i]<=k)
					dp[i][j][k]=max(max(dp[i-1][j][k],dp[i][j][k-1]),dp[i-1][j][k-a[i]]+1);
				else
					dp[i][j][k]=max(dp[i-1][j][k],dp[i][j][k-1]);
				//printf("%d ",dp[i][j][k]);
			}
			//printf("\n");
		}
		//printf("\n");
	}
	printf("%d",dp[n][m][t]);
	return 0;
}
